ALTER STATISTICS s1 SET STATISTICS 100;
ALTER STATISTICS IF EXISTS s1 SET STATISTICS 100;
ALTER STATISTICS s1 OWNER TO current_user;
ALTER STATISTICS s1 RENAME TO s2;
